#include<bits/stdc++.h>
#define ve vector<int>
#define ve_long_long vector<long long>
#define gr greater<int>
#define gr_long_long greater<long long>
#define le less<int>
#define le_long_long less<long long>
#define pi acos(-1.0)
#define ms multiset<int>
#define ms_long_long multiset<long long>
#define fo(l,r) for(int i=l;i<=r;i++)
#define ll long long
#define Pair pair<int,int>
#define Pair_long_long pair<long long,long long>
#define Small_root_pile  priority_queue<int,vector<int>,greater<int> >
#define Large_root_pile  priority_queue<int>
#define Small_root_pile_long_long  priority_queue<long long,vector<long long>,greater<long long> >
#define Large_root_pile_long_long  priority_queue<long long>
#define pr(a) printf("%d",a);
#define pu(a) printf("%d\n",a);
#define me(a,b) memset(a,b,sizeof(a));
using namespace std;
int a[100010],b[100010];
struct node
{
	int val,id1,id2;
	friend bool operator<(const node x,const node y)
	{
		return x.val>y.val;
	}
};
priority_queue<node> q;
int main()
{
	int n;
	scanf("%d",&n);
	for(int i=1;i<=n;i++)
	{
		scanf("%d",&a[i]);
	}
	for(int i=1;i<=n;i++)
	{
		scanf("%d",&b[i]);
	}
	for(int i=1;i<=n;i++)
	{
		q.push((node){a[1]+b[i],1,i});
	}
	for(int i=0;i<n;i++)
	{
		node temp=q.top();
		q.pop();
		printf("%d ",temp.val);
		temp.id1++;
		temp.val=a[temp.id1]+b[temp.id2];
		q.push(temp);
	}
	return 0;
}
